const childWorkflows = ['CWF-610', 'CWF-620', 'CWF-630'];
let executionPlan = { workflows_to_execute: childWorkflows, current_index: 0, status: 'PLANNING', async_collection_allowed: true, loop_closure_required: true };
return [{ json: { ...$json, execution_plan: executionPlan, pack_orchestration: { started_at: new Date().toISOString(), expected_duration_seconds: 180 } } }];

const childResults = { CWF_610: $json.cwf610_result, CWF_620: $json.cwf620_result, CWF_630: $json.cwf630_result };
const allHealthy = Object.values(childResults).filter(r => r).every(r => r?.status === 'SUCCESS' || r?.status === 'COMPLETED' || r?.status === 'PARTIAL');
const metricsCollected = $json.cwf610_result?.payload?.metrics_collected === true || $json.cwf610_result?.payload?.partial_metrics === true;
const feedbackAggregated = $json.cwf620_result?.payload?.feedback_aggregated === true;
const signalsSynthesized = $json.cwf630_result?.payload?.signals_synthesized === true;
const loopClosed = $json.cwf630_result?.payload?.loop_closure_defined === true;
const validationOk = allHealthy && metricsCollected && feedbackAggregated && signalsSynthesized && loopClosed;
return [{ json: { ...$json, pack_validation: { child_results_aggregated: childResults, all_children_healthy: allHealthy, metrics_collected: metricsCollected, feedback_aggregated: feedbackAggregated, signals_synthesized: signalsSynthesized, loop_closed: loopClosed, validation_ok: validationOk, route_to_error: !validationOk } } }];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    dossier_write: {
      mutation_type: 'namespace_update',
      target: 'dossier.analytics',
      timestamp: new Date().toISOString(),
      writer_id: 'WF-600',
      pack_context: $json.pack_context,
      child_results: $json.pack_validation.child_results_aggregated,
      audit_entry: 'analytics-evolution-pack-completion from WF-600'
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_route_runs_write: {
      operation: 'record_pack_execution',
      pack_id: 'WF-600',
      dossier_id: $json.dossier_id,
      child_workflows_executed: ['CWF-610', 'CWF-620', 'CWF-630'],
      execution_status: 'COMPLETED',
      metrics_collected: $json.pack_validation.metrics_collected,
      loop_closed: $json.pack_validation.loop_closed,
      timestamp: new Date().toISOString()
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-600',
    execution_status: 'SUCCESS',
    completion_packet: {
      instance_id: 'WF-600-COMP-' + Date.now(),
      artifact_family: 'analytics_evolution_result',
      schema_version: '1.0.0',
      producer_workflow: 'WF-600',
      dossier_ref: $json.dossier_id,
      created_at: new Date().toISOString(),
      status: 'CREATED',
      payload: {
        pack_executed: 'WF-600',
        metrics_collected: $json.pack_validation.metrics_collected,
        feedback_aggregated: $json.pack_validation.feedback_aggregated,
        signals_synthesized: $json.pack_validation.signals_synthesized,
        loop_closed: $json.pack_validation.loop_closed,
        child_packets: ['CWF-610_output', 'CWF-620_output', 'CWF-630_output']
      }
    }
  }
}];

if (!$json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-600',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: 'Pack validation failed or analytics synthesis failed',
    failure_context: $json.pack_validation,
    child_results: $json.pack_validation.child_results_aggregated
  }
}];
